import { Component, Host, h } from '@stencil/core';

/**
 * Popover provides ability to project HTML as a content which can be achieved using this component.
 * Example:
 * <kds-popover placement="top" alignment="center">
 <button type="button">popover</button>
 <kds-popover-content>
 <div>
 Popover content text/html
 </div>
 </kds-popover-content>
 </kds-popover>
 */
@Component({
  tag: 'kds-popover-content',
  styleUrl: 'kds-popover-content.css'
})
export class KdsPopoverContent {
  render() {
    return (
      <Host class='bg-default-50 border border-neutral-less-prominent kds-popover-content'>
        <div class='kds-popover-body'>
          <slot />
        </div>
      </Host>
    );
  }
}
